/// <summary>
/// Controller class for the process "Import warehouse outputs"
/// of transfer journals for the ETGSPAIN model.
/// </summary>
class ETGSPAINInventJournalLineImportController extends SysOperationServiceController
{
}

Method.Source:
/// <summary>
/// Method to create a new instance of the class.
/// </summary>
public void new()
{
    super(classStr(ETGSPAINInventJournalLineImportService),
        methodStr(ETGSPAINInventJournalLineImportService, processOperation),
        SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// <c>defaultCaption</c> method to display the process description.
/// </summary>
public ClassDescription defaultCaption()
{
    return "@ETGSPAINLabels:InventJournalLineImport";
}

/// <summary>
/// <c>main</c> method, invoked from the MenuItem to execute the service.
/// </summary>
/// <param name = "_args">Args</param>
public static void main(Args _args)
{
    ETGSPAINInventJournalLineImportController       controller;
    ETGSPAINInventJournalLineImportContract         contract;
    InventJournalTable                              inventJournalTable = _args.record();

    controller = new ETGSPAINInventJournalLineImportController();
    controller.parmArgs(_args);
    controller.parmLoadFromSysLastValue(false);
    controller.showBatchTab(false);

    contract = controller.getDataContractObject('_contract');
    contract.parmInventJournalId(inventJournalTable.JournalId);

    controller.startOperation();

    controller.refreshCallingForm(_args);
}

/// <summary>
/// Updates the form from which the process was called.
/// </summary>
/// <param name="_args">Arguments passed to the form</param>
private void refreshCallingForm(Args _args)
{
    FormDataSource formDataSource;

    if (_args && _args.record() && _args.record().isFormDataSource())
    {
        formDataSource = _args.record().dataSource();
        formDataSource.research(true);
    }
}
